--- 请求装配纹章
function LxCrestHandler:CrestDressReq(sid, position)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.CrestDressReq)
    proto.sid = sid
    proto.position = position
    SendMessage(LxProtoIds.CrestDressReq, proto)
end
--- 请求脱下纹章
function LxCrestHandler:CrestDropReq( position)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.CrestDropReq)
    proto.position = position
    SendMessage(LxProtoIds.CrestDropReq, proto)
end
--- 纹章升阶
function LxCrestHandler:CrestGradeUpReq(sid,refId, position)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.CrestGradeUpReq)
    proto.sid = sid
    proto.refId = refId
    proto.position = position
    SendMessage(LxProtoIds.CrestGradeUpReq, proto)
end
--- 纹章收集激活节点
function LxCrestHandler:CrestCollectActiveReq(type)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.CrestCollectActiveReq)
    proto.type = type
    SendMessage(LxProtoIds.CrestCollectActiveReq, proto)
end

