--- s2c
---
function LxCrestHandler:OnCrestDressResp(pb)
    if pb.crest then
        ModuleCenter.Crest:AddCrest(pb.crest)
    end
    if pb.oldCrest then
        ModuleCenter.Crest:AddCrest(pb.oldCrest)
    end
end

function LxCrestHandler:OnCrestGradeUpResp(pb)
    if pb.crest then
        local oldCrest = ModuleCenter.Crest:GetCrest(pb.crest.refId)
        local oldGrade = oldCrest and oldCrest.grade or 0
        ModuleCenter.Crest:AddCrest(pb.crest)
        local newGrade = checknumber(pb.crest.grade)
        if oldGrade ~= newGrade then
            FireEvent(EventNames.CREST_UPGRADE,{refId = pb.crest.refId,oldGrade = oldGrade,newGrade = newGrade})
            -- ShowPanel(UiNames.CrestAdvanceSuc,{refId = pb.crest.refId,oldGrade = oldGrade,newGrade = newGrade})
        end
    end
end

function LxCrestHandler:OnCrestCollectActiveResp(pb)
    local collectId = pb.collectObj
    local oldAttrRef = GameTable.CrestCollectRef[ModuleCenter.Crest:GetCollectIdByType(collectId.type).refId]
    oldAttrRef = oldAttrRef and LxDataHelper.ParseAttrList(oldAttrRef.attribute) or {}
    local newAttr = GameTable.CrestCollectRef[collectId.refId]
    newAttr = newAttr and LxDataHelper.ParseAttrList(newAttr.attribute) or {}
    ModuleCenter.Crest:SetCollectId(collectId)
    FireEvent(EventNames.CREST_COLLECT_UPDATE)

    ShowPanel(UiNames.FloatAttr, {old = oldAttrRef, new = newAttr})
end

function LxCrestHandler:OnCrestChangeResp(pb)
    for i, crestPb in ipairs(pb.addCrests) do
        ModuleCenter.Crest:AddCrest(crestPb)
    end
end

function LxCrestHandler:OnCrestDropResp(pb)
    if pb.crest then
        ModuleCenter.Crest:AddCrest(pb.crest)
    end
end

return LxCrestHandler